/**
 * Password visibility toggle -- progressive enhancement.
 *
 * No-JS baseline: password + confirm password fields work normally.
 * With JS: a toggle button replaces the confirm field. When password
 * is visible, the user can see what they typed, so confirmation is
 * unnecessary. When hidden again, confirm field returns.
 *
 * A11y:
 * - Toggle is a <button type="button"> (not a checkbox or link)
 * - aria-pressed communicates toggle state to screen readers
 * - aria-label describes the action ("Show password" / "Hide password")
 * - Focus remains on the toggle after activation
 */
(function () {
  "use strict";

  var passwordInput = document.getElementById("password");
  var confirmGroup = document.getElementById("confirm-group");

  // Only enhance if both elements exist (registration page)
  if (!passwordInput || !confirmGroup) {
    return;
  }

  // Store the confirm group's position in the DOM
  var confirmGroupParent = confirmGroup.parentNode;
  var confirmGroupNextSibling = confirmGroup.nextSibling;

  // Create a hidden input to mirror the password value when confirm field is removed.
  // Without this, the form won't send password_confirmation and the server rejects it.
  var hiddenConfirm = document.createElement("input");
  hiddenConfirm.type = "hidden";
  hiddenConfirm.name = "password_confirmation";

  // Create the toggle button
  var toggle = document.createElement("button");
  toggle.type = "button";
  toggle.className = "password-toggle";
  toggle.setAttribute("aria-label", "Show password");
  toggle.setAttribute("aria-pressed", "false");
  toggle.textContent = "Show password";

  // Insert toggle after the password input's parent group
  var passwordGroup = passwordInput.closest(".auth-form__group");
  if (!passwordGroup) {
    return;
  }
  passwordGroup.appendChild(toggle);

  // Remove the confirm group and add hidden mirror (JS is working, toggle replaces it)
  confirmGroup.remove();
  hiddenConfirm.value = passwordInput.value;
  passwordGroup.appendChild(hiddenConfirm);

  // Keep the hidden input in sync as the user types
  passwordInput.addEventListener("input", function () {
    if (hiddenConfirm.parentNode) {
      hiddenConfirm.value = passwordInput.value;
    }
  });

  toggle.addEventListener("click", function () {
    var isPressed = toggle.getAttribute("aria-pressed") === "true";

    if (isPressed) {
      // Hide password: restore confirm field, remove hidden mirror
      passwordInput.type = "password";
      toggle.setAttribute("aria-pressed", "false");
      toggle.setAttribute("aria-label", "Show password");
      toggle.textContent = "Show password";

      if (hiddenConfirm.parentNode) {
        hiddenConfirm.remove();
      }

      // Restore the confirm group
      if (confirmGroupNextSibling) {
        confirmGroupParent.insertBefore(confirmGroup, confirmGroupNextSibling);
      } else {
        confirmGroupParent.appendChild(confirmGroup);
      }
    } else {
      // Show password: remove confirm field, add hidden mirror
      passwordInput.type = "text";
      toggle.setAttribute("aria-pressed", "true");
      toggle.setAttribute("aria-label", "Hide password");
      toggle.textContent = "Hide password";

      // Remove the confirm group
      confirmGroup.remove();

      // Add hidden input mirroring the password value
      hiddenConfirm.value = passwordInput.value;
      passwordGroup.appendChild(hiddenConfirm);
    }
  });
})();

use crate::helpers::spawn_app;

#[tokio::test]
async fn get_register_returns_200_with_registration_form() {
    let app = spawn_app().await;

    let client = reqwest::Client::new();
    let response = client
        .get(format!("{}/register", &app.address))
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(response.status().as_u16(), 200);

    let content_type = response
        .headers()
        .get("content-type")
        .expect("Missing content-type header")
        .to_str()
        .unwrap();
    assert!(
        content_type.contains("text/html"),
        "Expected text/html, got {content_type}"
    );

    let body = response.text().await.unwrap();

    // Page structure
    assert!(body.contains("Create account"), "Missing page heading");
    assert!(
        body.contains("Create account -- Todo List"),
        "Missing descriptive page title"
    );

    // Form fields with labels
    assert!(
        body.contains("<label for=\"email\">Email</label>"),
        "Missing email label"
    );
    assert!(body.contains("type=\"email\""), "Missing email input");
    assert!(
        body.contains("<label for=\"password\">Password</label>"),
        "Missing password label"
    );
    assert!(
        body.contains("autocomplete=\"new-password\""),
        "Missing autocomplete=\"new-password\" on password fields"
    );
    assert!(
        body.contains("<label for=\"password_confirmation\">Confirm password</label>"),
        "Missing password confirmation label"
    );

    // Submit button with action words
    assert!(
        body.contains(">Create account</button>"),
        "Submit button should say 'Create account'"
    );

    // Link to login
    assert!(body.contains("Sign in"), "Missing link to login page");
    assert!(body.contains("href=\"/login\""), "Missing login link href");

    // Accessibility: no error states on initial load
    assert!(
        !body.contains("aria-invalid=\"true\""),
        "Should not have aria-invalid=\"true\" on initial load"
    );
    // Error containers exist (for aria-describedby targets) but should be empty
    assert!(
        !body.contains("Enter your email address"),
        "Should not show email error text on initial load"
    );
    assert!(
        !body.contains("at least 8 characters</p>"),
        "Should not show password error text on initial load"
    );
}

#[tokio::test]
async fn post_register_with_valid_data_redirects() {
    let app = spawn_app().await;

    let client = reqwest::Client::builder()
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    let response = client
        .post(format!("{}/register", &app.address))
        .form(&[
            ("email", "test@example.com"),
            ("password", "securepassword123"),
            ("password_confirmation", "securepassword123"),
        ])
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(
        response.status().as_u16(),
        303,
        "Expected 303 See Other redirect after successful registration"
    );
}

#[tokio::test]
async fn post_register_persists_user_in_database() {
    let app = spawn_app().await;

    let client = reqwest::Client::builder()
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    client
        .post(format!("{}/register", &app.address))
        .form(&[
            ("email", "persist@example.com"),
            ("password", "securepassword123"),
            ("password_confirmation", "securepassword123"),
        ])
        .send()
        .await
        .expect("Failed to execute request");

    let saved = sqlx::query!(
        "SELECT email, password_hash FROM users WHERE email = $1",
        "persist@example.com"
    )
    .fetch_one(&app.pool)
    .await
    .expect("Failed to fetch saved user");

    assert_eq!(saved.email, "persist@example.com");
    assert!(
        saved.password_hash.starts_with("$argon2"),
        "Password should be hashed with Argon2"
    );
}

#[tokio::test]
async fn post_register_returns_422_when_email_is_empty() {
    let app = spawn_app().await;

    let client = reqwest::Client::new();
    let response = client
        .post(format!("{}/register", &app.address))
        .form(&[
            ("email", ""),
            ("password", "securepassword123"),
            ("password_confirmation", "securepassword123"),
        ])
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(response.status().as_u16(), 422);
    let body = response.text().await.unwrap();
    assert!(
        body.contains("Enter your email address"),
        "Should show email error message"
    );
}

